Rules.InvariantScript:
Refresh(EmergencyIncidents);
Reset(galIncidentOverview);
Notify("Incident list refreshed.", NotificationType.Success)

Set(
    varSelectedIncident,
    LookUp(EmergencyIncidents, ID = ThisItem.ID)
);

If(
    ThisItem.Status.Value = "On the Way",
    Navigate(DispatchTrackingScreen, ScreenTransition.Fade),
    Navigate(ActiveIncidentScreen, ScreenTransition.Fade)
)
